INSERT INTO `flags` (`flag_id`, `slug`, `name`, `description`, `flag_color`, `default_weight`, `is_active`, `sort_order`, `created_at`, `updated_at`, `category_id`) VALUES (175,'medicare-for-all','Medicare for All','Explicit support for universal single-payer healthcare.','green',5.00,1,10,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(176,'abortion-rights','Abortion Rights','Strong support for abortion access and opposition to abortion bans.','green',5.00,1,20,'2026-03-17 14:29:55','2026-03-17 14:29:55',34),(177,'labor-rights','Labor Rights','Strong pro-union record, collective bargaining support, and opposition to union busting.','green',5.00,1,30,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(178,'voting-rights','Voting Rights','Supports expanding ballot access and opposes voter suppression.','green',5.00,1,40,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(179,'lgbtq-equality','LGBTQ Equality','Strong support for LGBTQ rights, including trans protections.','green',5.00,1,50,'2026-03-17 14:29:55','2026-03-17 14:29:55',34),(180,'anti-aipac','Opposes AIPAC Influence','Rejects AIPAC influence and opposes unconditional U.S. support for Israeli government actions.','green',5.00,1,60,'2026-03-17 14:29:55','2026-03-17 14:29:55',39),(181,'climate-action','Climate Action','Supports major climate policy, emissions cuts, and clean energy investment.','green',5.00,1,70,'2026-03-17 14:29:55','2026-03-17 14:29:55',37),(182,'anti-corruption','Anti-Corruption','Supports strong ethics rules, lobbying limits, and anti-corruption reforms.','green',4.00,1,80,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(183,'campaign-finance-reform','Campaign Finance Reform','Supports stronger campaign finance laws and reducing big-money influence.','green',4.00,1,90,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(184,'no-corporate-pac','No Corporate PAC Money','Refuses corporate PAC money or materially limits corporate influence.','green',4.00,1,100,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(185,'gun-safety','Gun Safety','Supports meaningful gun safety laws such as background checks and assault weapon restrictions.','green',4.00,1,110,'2026-03-17 14:29:55','2026-03-17 14:29:55',38),(186,'immigrant-rights','Immigrant Rights','Supports humane immigration policy and opposes cruelty-based enforcement.','green',4.00,1,120,'2026-03-17 14:29:55','2026-03-17 14:29:55',38),(187,'racial-justice','Racial Justice','Supports civil rights enforcement and policies addressing systemic racial inequity.','green',4.00,1,130,'2026-03-17 14:29:55','2026-03-17 14:29:55',34),(188,'housing-affordability','Housing Affordability','Supports stronger affordable housing and anti-homelessness policy.','green',3.00,1,140,'2026-03-17 14:29:55','2026-03-17 14:29:55',37),(189,'public-education','Public Education','Strong support for public schools and opposition to privatization schemes.','green',3.00,1,150,'2026-03-17 14:29:55','2026-03-17 14:29:55',37),(190,'minimum-wage','Living Wage','Supports raising the minimum wage to a real living standard.','green',3.00,1,160,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(191,'student-debt-relief','Student Debt Relief','Supports meaningful relief or cancellation for student borrowers.','green',3.00,1,170,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(192,'criminal-justice-reform','Criminal Justice Reform','Supports sentencing reform, police accountability, and reducing mass incarceration.','green',3.00,1,180,'2026-03-17 14:29:55','2026-03-17 14:29:55',38),(193,'ceasefire-human-rights','Human Rights Foreign Policy','Supports conditioning aid on human rights and rejects blank-check militarism.','green',3.00,1,190,'2026-03-17 14:29:55','2026-03-17 14:29:55',39),(194,'anti-abortion','Anti-Abortion','Supports abortion bans or major abortion restrictions.','red',5.00,1,210,'2026-03-17 14:29:55','2026-03-17 14:29:55',34),(195,'anti-lgbtq','Anti-LGBTQ','Supports anti-LGBTQ policy, especially anti-trans attacks.','red',5.00,1,220,'2026-03-17 14:29:55','2026-03-17 14:29:55',34),(196,'voter-suppression','Voter Suppression','Supports voter suppression measures such as restrictive voter ID laws or roll purges.','red',5.00,1,230,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(197,'union-buster','Union Busting','Anti-union record or support for policies that weaken collective bargaining.','red',5.00,1,240,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(198,'climate-denial','Climate Denial','Denies climate science or obstructs major climate action.','red',5.00,1,250,'2026-03-17 14:29:55','2026-03-17 14:29:55',37),(199,'aipac-backed','AIPAC / Pro-Israel Lobby Backing','Accepts AIPAC support or aligns with unconditional pro-Israel government policy.','red',5.00,1,260,'2026-03-17 14:29:55','2026-03-17 14:29:55',39),(200,'corporate-pac','Corporate PAC Money','Reliance on corporate PAC money or clear corporate capture.','red',4.00,1,270,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(201,'anti-medicare-for-all','Anti-Universal Healthcare','Opposes universal healthcare and protects the private-insurance status quo.','red',4.00,1,280,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(202,'privatization','Privatization','Pushes privatization of public goods like schools, Social Security, or Medicare.','red',4.00,1,290,'2026-03-17 14:29:55','2026-03-17 14:29:55',37),(203,'corruption-scandal','Corruption','Credible corruption scandal, pay-to-play behavior, or major ethics issues.','red',4.00,1,300,'2026-03-17 14:29:55','2026-03-17 14:29:55',36),(204,'genocide-apologia','Human Rights Abuse Support','Supports or excuses major human-rights abuses or collective punishment abroad.','red',4.00,1,310,'2026-03-17 14:29:55','2026-03-17 14:29:55',39),(205,'anti-immigrant','Anti-Immigrant','Supports cruel anti-immigrant policy or demonizing rhetoric.','red',4.00,1,320,'2026-03-17 14:29:55','2026-03-17 14:29:55',38),(206,'anti-gun-safety','Opposes Gun Safety','Opposes even basic gun safety reforms.','red',3.00,1,330,'2026-03-17 14:29:55','2026-03-17 14:29:55',38),(207,'anti-minimum-wage','Anti-Living Wage','Opposes raising wages or sides with low-wage employer interests.','red',3.00,1,340,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(208,'anti-public-education','Anti-Public Education','Supports defunding or privatizing public education.','red',3.00,1,350,'2026-03-17 14:29:55','2026-03-17 14:29:55',37),(209,'anti-debt-relief','Anti-Debt Relief','Opposes meaningful student debt relief.','red',2.00,1,360,'2026-03-17 14:29:55','2026-03-17 14:29:55',35),(210,'carceral-politics','Carceral Politics','Favors punitive overreach, mass-incarceration posture, or police impunity.','red',2.00,1,370,'2026-03-17 14:29:55','2026-03-17 14:29:55',38),(239,'healthcare-access','Healthcare Access','Supports expanding or protecting access to healthcare.','green',1.00,1,0,'2026-03-22 11:50:53','2026-03-22 11:50:53',NULL);
